import{_ as a,o as t,c as o,al as r}from"./chunks/framework.DtH0F2t4.js";const m=JSON.parse('{"title":"Technology","description":"","frontmatter":{"layout":"page"},"headers":[],"relativePath":"technology.md","filePath":"technology.md"}'),i={name:"technology.md"};function l(n,e,s,h,p,d){return t(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="technology" tabindex="-1">Technology <a class="header-anchor" href="#technology" aria-label="Permalink to &quot;Technology&quot;">​</a></h1><p>eodash is the core framework, state manager and component communicator between both core and third-party widgets. It is based on <a href="https://vuejs.org/" target="_blank" rel="noreferrer">vue.js</a> (version 3).</p><p>The core widgets are built using <a href="https://eox-a.github.io/EOxElements/" target="_blank" rel="noreferrer">EOxElements</a> and are extended through how they interact with each other.</p><p>The state management within eodash is based on <a href="https://stacspec.org" target="_blank" rel="noreferrer">SpatioTemporal Asset Catalogs (STAC)</a>. Each component can register to a central store, provided by <a href="https://pinia.vuejs.org/" target="_blank" rel="noreferrer">pinia</a>.</p><p>eodash can be used either as a <a href="https://www.webcomponents.org/introduction" target="_blank" rel="noreferrer">web component</a> or as a package that can be build based on <a href="https://vitejs.dev/" target="_blank" rel="noreferrer">vite</a>.</p><h1 id="components" tabindex="-1">Components <a class="header-anchor" href="#components" aria-label="Permalink to &quot;Components&quot;">​</a></h1><ul><li><a href="https://eodash.github.io/eodash" target="_blank" rel="noreferrer">eodash</a><ul><li>library for eodash client instance creation and web component release</li><li>extendable and configurable through widgets</li></ul></li><li><a href="https://github.com/eodash/eodash_catalog" target="_blank" rel="noreferrer">eodash_catalog</a><ul><li>library for creation of STAC catalog supported by eodash</li><li>supports multiple backends and services</li></ul></li><li><a href="https://github.com/eodash/eodash-pages-template" target="_blank" rel="noreferrer">eodash-pages-template</a><ul><li>template repo showing how to instantiate eodash as part of a vitepress application</li></ul></li><li><a href="https://github.com/eodash/eodash-instance-template" target="_blank" rel="noreferrer">eodash-instance-template</a><ul><li>template repo showing how to integrate eodash as package for building and extension of functionality into a vite based application</li></ul></li><li><a href="https://github.com/eodash/catalog-template" target="_blank" rel="noreferrer">catalog-template</a><ul><li>template repo with example setup for a catalog configuration and deployment as github pages</li></ul></li><li><a href="https://github.com/eodash/eodash-docs" target="_blank" rel="noreferrer">eodash-docs</a><ul><li>central location for eodash ecosystem documentation</li></ul></li><li><a href="https://github.com/eodash/eodash-schemas" target="_blank" rel="noreferrer">eodash-schemas</a><ul><li>JSON schemas for eodash catalog configs for purposes of validation - matching <a href="https://github.com/eodash/eodash_catalog/wiki" target="_blank" rel="noreferrer">eodash catalog wiki entries</a></li></ul></li></ul><h1 id="roadmap-todo-shorten" tabindex="-1">Roadmap TODO shorten <a class="header-anchor" href="#roadmap-todo-shorten" aria-label="Permalink to &quot;Roadmap TODO shorten&quot;">​</a></h1><p>This project brings together experience and capabilities from work in the Earth Observation field. It will evolve iteratively, shaped by ongoing development and community interactions.</p><p>We welcome feedback and inputs through issues in respective components. If you are unsure where to create an issue, use the <a href="https://github.com/eodash/eodash/issues" target="_blank" rel="noreferrer">eodash issue board</a>.</p><p>To support discussion, here are key roadmap areas and topics.</p><ul><li>eodash <ul><li>Extend support for generic STAC catalogs</li><li>Develop eodash STAC catalog extension</li><li>Expand example (template) repositories for other frameworks</li><li>Implement support of flat styles for serverless datasets (COG and GeoJSON)</li><li>Explore supporting cloud optimized vector formats</li><li>Implement chart rendering of data based on <a href="https://vega.github.io/vega/" target="_blank" rel="noreferrer">VEGA chart definition language</a></li><li>Document how to implement a custom widget (as part of eodash instance template)</li></ul></li><li>catalog <ul><li>Introduce a plugin system</li><li>Document how to create custom plugins</li><li>Improve performance for very large collections</li><li>Evaluat a potential switch to a different base library</li></ul></li><li>storytelling <ul><li>Allow importing map state based on passed STAC item (and state modifiers)</li><li>Allow importing of chart state based on passed STAC item (and state modifiers)</li><li>Integrate VEGA chart definition rendering component</li><li>Improve documentation</li></ul></li><li>documentation <ul><li>Expand usage guides and examples</li><li>Add links to open example instances</li></ul></li><li>other <ul><li>Initiate the process of becoming an OSGeo Community Project</li><li>Create a library or helper UI to simplify creating flat styles (extended by eox-forms)</li><li>Implement (or wrap) VEGA chart definition rendering component</li><li>Add example images and animations to the documentation</li></ul></li></ul>',12)])])}const g=a(i,[["render",l]]);export{m as __pageData,g as default};
